const http = $input.first().json;
const rows = Array.isArray(http)
  ? http
  : Array.isArray(http.body)
    ? http.body
    : [];
if (!rows.length) return [];
return rows.map((event) => ({
  json: {
    event_id: event.id,
    platform: event.platform,
    attempts: typeof event.attempts === 'number' ? event.attempts : 0,
    team_id: event.team_id,
    workspace_id: event.workspace_id,
    raw_payload: event.raw_payload || {},
  },
}));

const event = $('Explode Events').item.json;
const forward = $input.first().json;
const statusCode = Number(forward.statusCode || forward.status || 0);
const nextAttempts = (event.attempts || 0) + 1;
const maxAttempts = 5;
const forwarded = statusCode >= 200 && statusCode < 300;

let patch;
if (forwarded) {
  patch = {
    status: 'processing',
    attempts: nextAttempts,
    last_attempt_at: new Date().toISOString(),
    error: null,
  };
} else if (nextAttempts >= maxAttempts) {
  patch = {
    status: 'failed',
    attempts: nextAttempts,
    last_attempt_at: new Date().toISOString(),
    error: 'replay_exhausted',
  };
} else {
  patch = {
    status: 'received',
    attempts: nextAttempts,
    last_attempt_at: new Date().toISOString(),
    error: 'replay_failed',
  };
}

return [{ json: { event_id: event.event_id, patch } }];
